"""
mkt-original — Joshua chapters 1–5
Run: python3 scripts/zc-original-joshua-1-5.py

Key Hebrew terms: Yehoshua (YHWH saves), chazaq ve'ematz (be strong and courageous),
sefer hatorah (scroll of the Torah), hagah (meditate), tatzliach (succeed/prosper),
meraglim (spies), tikvat chut hashani (scarlet cord of hope), hesed (loyal love),
aron habrit (ark of the covenant), adon kol ha'aretz (lord of all the earth),
avanim / zikaron (stones / memorial), milah (circumcision), gilgal (rolling),
pesach (Passover), sar-tzva-YHWH (commander of YHWH's army).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / f'mkt-{source}' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOSHUA = {
  "1": {
    "1": "<p>Joshua's Hebrew name (<em>Yehoshua</em>) means 'YHWH saves' — the same name as Jesus (Greek <em>Iēsous</em>, from the LXX transliteration of <em>Yehoshua</em>). The name-identity is not coincidental: Hebrews 4:8 uses the identity of names to make a theological argument ('if Joshua [<em>Iēsous</em>] had given them rest...'). Joshua is Israel's deliverer who leads the people into the promised land after Moses; the structural parallel anticipates Jesus, who leads his people into the ultimate rest that Canaan only shadowed. The book begins <em>va'yehi acharei mot Mosheh</em> — 'after the death of Moses' — marking the transition from the law-giving mediator to the conquest mediator.</p>",
    "2": "<p><strong>qum avor</strong> (<em>qum, H6965; avor, H5674</em>): 'arise and cross.' The double imperative launches the conquest: rise from the posture of waiting (sitting shiva for Moses) and cross the boundary (the Jordan). <em>Qum</em> (arise) is the word of new beginning after mourning, defeat, or sleep — used of resurrection in later theology. <em>Avor</em> (cross, pass over) uses the same root as the Passover (<em>pesach</em>) and the Exodus crossing. The command to 'go over this Jordan' inaugurates the third great crossing in Israel's story: the Red Sea (Exod 14), the Jordan (Josh 3-4), and the anticipation of the eschatological crossing into the true promised land.</p>",
    "3": "<p><strong>kol-makom asher tidrok kaf-raglekhem bo</strong> (<em>kaf-regel, H3709+7272</em>): 'every place the sole of your foot treads.' The land-grant is defined by active possession through movement — the foot that treads claims. The idiom implies total coverage: every terrain traversed becomes theirs. Behind this is the ancient ANE formula of land-grant by walking boundaries (Abraham walking through Canaan in Gen 13:17: 'arise, walk through the length and the breadth of it'). The promise 'I have given it to you' (<em>netati</em>, perfect tense) precedes the treading — the gift is already complete in YHWH's purpose; the treading is the claiming of what is already given.</p>",
    "4": "<p><strong>hamidbarmid lewvanon... nahar haGadol</strong> (<em>midbar, H4057; Levanon, H3844; nahar, H5104</em>): 'from the wilderness to Lebanon... to the great river.' The boundaries of the land-promise are given in their ideal extent — from the southern desert to the northern mountains, from the sea to the Euphrates. <em>Nahar haGadol</em> (the great river, i.e., the Euphrates) is the maximum boundary of the Davidic kingdom (2 Sam 8:3; 1 Kgs 4:21). The promise exceeds what the conquest will achieve in Joshua's lifetime; the ideal dimensions of the grant anticipate a fulfillment larger than the initial conquest — the Davidic-Solomonic expansion and ultimately the eschatological inheritance.</p>",
    "5": "<p><strong>lo-arpeka velo-e'ezveka</strong> (<em>raphah, H7503; azav, H5800</em>): 'I will not loosen you and I will not abandon you.' <em>Raphah</em> means to let go, release, or drop (the hands), implying ceasing to support or uphold. <em>Azav</em> means to forsake, leave behind, abandon. The double negative (<em>lo... velo</em>) is absolute: YHWH's commitment is not conditional. This verbatim promise is quoted in Heb 13:5 as the basis for Christian contentment without covetousness. What was spoken to Joshua as a conquest-promise becomes the ground of every believer's daily peace: the one who was with Joshua in the Jordan and at Jericho is the same one who is with his people in every circumstance.</p>",
    "6": "<p><strong>chazaq ve'ematz</strong> (<em>chazaq, H2388; amatz, H553</em>): 'be strong and courageous.' The paired command appears four times in this chapter (vv.6,7,9,18) — a rhetorical emphasis signaling that the conquest's primary challenge is not military but psychological and spiritual. <em>Chazaq</em> (be strong) is used of gripping, holding fast, prevailing — the strength of maintained hold rather than aggressive force. <em>Amatz</em> (be courageous) is used of the hardening of the face/heart for a difficult task — determination in the face of daunting odds. The command is not advice but commission: YHWH's word does not merely recommend courage but grants it by promising his presence (v.9: 'for YHWH your God is with you').</p>",
    "7": "<p><strong>lishmor la'asot</strong> (<em>shamar, H8104; asah, H6213</em>): 'to keep, to do.' The command to the Torah is double: <em>shamar</em> (guard, keep, watch over — the active preservation of what has been entrusted) and <em>asah</em> (do, perform, accomplish — the active execution). Together they cover the two aspects of faithfulness to YHWH's instruction: preservation and application, not letting it slip and not merely knowing it. <strong>lo tatir yamin usmol</strong> (<em>sur, H5493</em>): 'do not turn to the right or to the left.' The idiom of the straight path appears in Proverbs (4:27) and deuteronomic theology as the standard of covenant fidelity — the straight path is obedience; any deviation is apostasy.</p>",
    "8": "<p><strong>sefer hatorah hazeh</strong> (<em>sefer, H5612; Torah, H8451</em>): 'this scroll of the Torah.' <em>Sefer</em> (scroll/document) indicates the written form — not oral tradition but inscribed text. <em>Torah</em> (instruction/law) derives from <em>yarah</em> (to throw/direct, to teach) — YHWH's instruction that directs the way. <strong>hagita bo</strong> (<em>hagah, H1897</em>): 'you shall meditate on it.' <em>Hagah</em> is the sound of low vocalization — murmuring, muttering — implying reading aloud to oneself; it is used of a lion growling over its prey (Isa 31:4) and of the dove's cooing (Isa 59:11). Torah-meditation is not silent intellectual reflection but vocal, embodied engagement with the text. <strong>vehayyah derachecha tatzliach</strong>: 'and you will make your way prosperous' — <em>tatzliach</em> (H6743) means success, prosperity, achieving the intended goal.</p>",
    "9": "<p><strong>al-te'aretz ve'al-techat</strong> (<em>arats, H6206; chatat, H2865</em>): 'do not be terrified and do not be dismayed.' <em>Arats</em> is to tremble in terror, to be overwhelmed with dread. <em>Chatat</em> is to be shattered, broken, dismayed — the internal collapse before external threat. Both words describe the psychological experience of facing overwhelming opposition. The antidote is not training or strategy but the covenant promise: <em>ki imcha YHWH Elohekha</em> (for YHWH your God is with you) — wherever you go. The presence of YHWH is not a resource to be accessed in crisis but a permanent reality that transforms the meaning of every circumstance. The conquest's success is ultimately YHWH's, not Israel's.</p>",
    "10": "<p><strong>vayetzav Yehoshua et-shotrei ha'am</strong> (<em>tzavah, H6680; shoter, H7860</em>): 'Joshua commanded the officers of the people.' <em>Shotrim</em> (officers/officials, singular <em>shoter</em>) were administrative officials responsible for organizing and communicating commands — analogous to NCOs in a military structure. They functioned alongside the elders (zekenim) and the judges (shoftim) in Israel's plural leadership structure. The command passes through the official chain: YHWH → Joshua → officers → people. The distribution of authority through intermediaries is the organizational pattern YHWH established at Sinai (Exod 18:13-27) and maintains through the conquest.</p>",
    "11": "<p><strong>tzedu lachem tzedah</strong> (<em>tzedah, H6720</em>): 'prepare provisions for yourselves.' <em>Tzedah</em> is food for a journey, travel-provisions — the practical preparation for a significant undertaking. The three-day timeline (v.11: 'within three days you will cross') creates urgency. The three days before the Jordan crossing mirrors the three days before the Passover night and the three days before Sinai — in the Exodus narrative, three days of preparation precede each major divine act. The people are commanded to be practically ready (food) and spiritually consecrated (5:2-12) before YHWH acts. Preparation and consecration are both required; neither alone is sufficient.</p>",
    "12": "<p><strong>Reuveniyim vehaGadiy vechatzi shevet Menashe</strong>: Reubenites, Gadites, and half-tribe of Manasseh — the trans-Jordan tribes. Their conditional inheritance (east bank) was granted in Numbers 32 on the promise that their fighting men would cross with Israel as <em>chalutzim</em> (armed fighters) until the conquest was complete. The arrangement tests the principle that the community's needs take priority over one's own secured portion — those who already have their inheritance are obligated to help the rest obtain theirs before settling. The trans-Jordan tribes fulfill this obligation here; later texts (Josh 22) record their faithful completion of the commitment.</p>",
    "13": "<p><strong>zachor et-hadavar</strong> (<em>zachar, H2142</em>): 'remember the word.' <em>Zachar</em> (remember) in Hebrew is not merely cognitive recall but active fidelity — to remember is to act in accordance with what was said. Joshua calls the two-and-a-half tribes to 'remember' Moses's command, meaning to now enact it. The command of Moses (Num 32:20-22) becomes the binding obligation of Joshua's moment. The continuity between Mosaic instruction and Joshuanic execution is essential to the book's theology: Joshua does not innovate but implements what Moses commanded, just as Moses had implemented what YHWH commanded. The chain of faithful transmission is the pattern of covenant leadership.</p>",
    "14": "<p><strong>gibbore hachayil</strong> (<em>gibbor, H1368; chayil, H2428</em>): 'men of valor/warriors of substance.' <em>Gibbor</em> (warrior, mighty man) is the term for the heroic warriors of the ancient world — Nimrod was a <em>gibbor</em> before YHWH (Gen 10:9), David's mighty men were <em>gibbore hachayil</em> (2 Sam 23). <em>Chayil</em> encompasses both strength and moral substance — it is used of Ruth's virtue ('woman of chayil,' Ruth 3:11) and Israel's warriors. The trans-Jordan fighters are not conscripts but an elite force: their prior military experience (the Transjordan campaigns of Numbers 32) qualifies them for the vanguard role in the Canaan conquest.</p>",
    "15": "<p><strong>ad asher yaniyach YHWH la'acheikem</strong> (<em>nuach, H5117</em>): 'until YHWH gives rest to your brothers.' <em>Nuach</em> (rest, settle, be at ease) is the conquest's telos — the goal of all the warfare is not victory as an end but rest as the destination. The verb <em>nuach</em> gives us the noun <em>menucha</em> (resting place, rest) which Deuteronomy uses for the promised land (Deut 12:9) and which Hebrews 4 uses for the eschatological sabbath. The trans-Jordan tribes must wait for their own settled rest until their brothers obtain theirs — a corporate understanding of shalom that does not permit individual security while the community remains unsettled.</p>",
    "16": "<p><strong>kol asher tzivitanu na'aseh</strong> (<em>tzavah, H6680; asah, H6213</em>): 'everything you have commanded us we will do.' The people's response to Joshua's commissioning is a formal statement of allegiance — the covenant-loyalty formula that mirrors the Sinai response (Exod 19:8; 24:3,7: 'all that YHWH has spoken we will do'). The repetition is deliberate: the book of Joshua begins with Israel renewing the Sinai commitment under new leadership. The transition from Moses to Joshua is authenticated by the people's identical response to Joshua's authority as they gave to Moses's. Leadership succession in Israel is not biological but covenantal — the people bind themselves to the one YHWH has appointed.</p>",
    "17": "<p><strong>raq yihyeh YHWH Elohekha imach</strong>: 'only may YHWH your God be with you.' The conditional of the people's full obedience: everything we promised, <em>provided</em> YHWH is with you as he was with Moses. The condition is not insolent but theologically precise — the people's obedience to Joshua is grounded in YHWH's commission of Joshua. They will follow Joshua because YHWH follows Joshua; if YHWH does not go with him, there is no obligation to follow him. This is the OT's clearest articulation of the derivative nature of human leadership in the covenant community: Joshua's authority exists only insofar as he is YHWH's appointed servant, confirmed by YHWH's presence with him.</p>",
    "18": "<p><strong>kol-ish asher yamreh et-pikh</strong> (<em>marah, H4784</em>): 'any man who rebels against your command.' <em>Marah</em> is the word for bitter rebellion — the same root as Miriam (<em>Miryam</em>, connected to bitterness) and the waters of Marah (Exod 15:23). The punishment for rebellion against Joshua's command is death — the same standard as rebellion against Moses. The people seal their commitment with a capital-punishment clause: they are not simply promising compliance but making a formal covenant oath. The chapter closes with the triple emphasis: obey, be strong and courageous, YHWH is with you. The three elements of the commission are confirmed by the community's binding pledge.</p>"
  },
  "2": {
    "1": "<p><strong>meraglim</strong> (<em>ragal, H7270</em>): 'spies.' <em>Meraglim</em> (spies/scouts) shares its root with <em>regel</em> (foot) — one who goes on foot to observe, or one who uses the feet for covert movement. The word also appears in the negative episode of Numbers 13-14 (the twelve spies). The Jericho spy mission is intentionally contrasted with the Numbers 13 disaster: there, twelve went and returned with a faithless report; here, two go and return with a faithful report. <strong>Rachav</strong> (<em>rachav, H7343</em>): the name may relate to <em>rachav</em> (H7342, wide/broad) or stand as a personal name. She is identified as a prostitute (<em>zonah</em>, H2181) — an outsider to Israel who becomes a model of faith (Heb 11:31; Jas 2:25).</p>",
    "2": "<p><strong>hineh anashim ba'u halailah</strong>: 'behold, men came here tonight.' The king of Jericho's intelligence network functions efficiently — the spies were observed entering Rahab's house. The verb <em>ba'u</em> (they came) is the standard arrival formula; <em>halailah</em> (tonight) adds urgency. The city's security apparatus — king, report, agents — represents the organized power of Canaanite civilization that YHWH is about to dismantle. The irony is that the spies who came to observe Jericho find that Jericho has already observed them; the intelligence mission succeeds not through superior tradecraft but through the faith of a single insider who shelters them.</p>",
    "3": "<p><strong>hozi'a et-ha'anashim hayvo'im elayich</strong>: 'bring out the men who came to you.' The king's demand is direct and official. The word <em>hotz'i</em> (bring out, from <em>yatza</em>/H3318) uses the same root as the Exodus formula (<em>hotzeiti</em>, I brought out — YHWH brings Israel out of Egypt). The royal command to 'bring out' those who came in foreshadows the great reversal: in the Exodus, YHWH brought his people out from Egyptian authority; in Jericho, a Canaanite woman defies royal authority to protect YHWH's servants. The same word carries opposite theological valence depending on who issues the command and in whose service it is obeyed.</p>",
    "4": "<p><strong>vattitzpon ha'ishah et-shnei ha'anashim</strong> (<em>tzaphan, H6845</em>): 'the woman hid the two men.' <em>Tzaphan</em> (to hide, conceal) is also the root of Zephaniah (<em>Tzefanyah</em>, YHWH has hidden/treasured). To hide something is to treasure and protect it. Rahab's act of hiding is at the same time an act of faith and an act of political treason — she conceals agents of the enemy nation from her own king. The same root appears in the Passover protection: YHWH hid Moses's mother (Exod 2:2), Rahab hid the spies, the scarlet cord marks the hidden household for protection. The divine pattern of hiding/sheltering the vulnerable recurs throughout the conquest narrative.</p>",
    "5": "<p><strong>kif'mot hashoar lisgor bachoshech</strong>: 'about the time of the gate-closing, at dark.' The temporal precision is important: the king's agents arrive at the moment Rahab claims the spies just left — the precise detail that makes her deception credible. The city gates were closed at dusk as a standard security measure in ancient Near Eastern cities. Rahab's claim that the spies 'went out when the gate was about to be shut' is unverifiable to the king's men without examining the gate records. The timing creates the plausible deniability that enables the deception. The narrative treats the deception without moral commentary — the canonical evaluation is given elsewhere (Heb 11:31; Jas 2:25), where her faith, not her method, is praised.</p>",
    "6": "<p><strong>vehishtil heeletha al-hagag uvtmenam pishte ha'etz</strong>: 'she had taken them up to the roof and hidden them with the stalks of flax.' The practical detail of the hiding place — flax stalks laid out on the roof for drying — is an authentic detail of Canaanite agricultural practice. Flax was harvested in spring (March-April), which matches the pre-Passover timing of the conquest (Josh 5:10). The roof served both agricultural (drying) and domestic (sleeping in hot weather) purposes. Rahab used an ordinary domestic feature for an extraordinary act of protection. The mundane (flax drying on a roof) becomes the vehicle of divine providence — a pattern repeated throughout the conquest narrative.</p>",
    "7": "<p><strong>va'anashim radfu achareihem</strong>: 'the men pursued after them.' The pursuit of the spies by Jericho's forces is the narrative's tension mechanism — the chase that will be resolved by the closed gate and the three-day hiding. The Jordan crossings (ford, <em>ma'avrot</em>, H4569) were the vulnerable points of Israel's advance; anyone trying to cross back could be intercepted. YHWH's protection of the spies operates through ordinary means: Rahab's deception, the flax stalks, the rope out the window. The protection is real but the means are human. The faith required is not faith in miraculous intervention but faith that YHWH's purpose will be accomplished through ordinary obedient action.</p>",
    "8": "<p><strong>beterem yishkavun</strong>: 'before they lay down.' Rahab approaches the hidden spies before sleep — the moment of maximum vulnerability when the city is quiet and the roof is private. The timing enables the speech that follows: Rahab's declaration of faith in vv.9-11 is one of the most remarkable confessions in the OT, spoken by a Canaanite prostitute who has seen and heard more of YHWH's work than most Israelites of her generation. Her faith is firsthand-evidence-based: she has <em>heard</em> (v.10) of the Red Sea and the Amorite defeats, and what she has heard has produced genuine fear-of-YHWH that the rest of Jericho shares but does not act on.</p>",
    "9": "<p><strong>natan YHWH lachem et-ha'aretz</strong>: 'YHWH has given you the land.' Rahab uses the divine name YHWH and the perfect tense (<em>natan</em>, has given) — the gift is already accomplished in her understanding. This is remarkable: an unreached Canaanite woman articulates the theology of the land-grant more clearly than most of the first wilderness generation did. <strong>veyiphal levaveinu</strong> (<em>yapal, H4127</em>): 'our hearts melted/fainted.' <em>Yapal</em> is the word for the complete dissolution of resolve — the heart literally drops. The same word describes the wilderness spies' effect on Israel (Num 13:28 variant). Here the Canaanites' terror confirms what YHWH promised Moses: 'I will put terror of you on the peoples' (Exod 15:15-16).</p>",
    "10": "<p><strong>shamanu asher hovish YHWH et-mei yam-suf</strong> (<em>hoviash, H3001; yam suf, H3220+5488</em>): 'we heard how YHWH dried up the water of the Sea of Reeds.' <em>Hoviash</em> (he dried up) uses the <em>hiphil</em> (causative) of <em>yavesh</em> (to be dry) — YHWH as the active agent of the drying. <em>Yam suf</em> (Sea of Reeds/Red Sea) is the technical name for the first great crossing. The connection Rahab draws — Red Sea crossing → Jordan crossing → conquest — is the chain of YHWH's acts that constitute the redemptive narrative. The events are not isolated miracles but a connected story of YHWH's faithfulness to his promise. Rahab has correctly understood the narrative arc.</p>",
    "11": "<p><strong>ki YHWH Eloheichem hu Elohim bashamayim mimaal uve'aretz mitachat</strong>: 'for YHWH your God is God in heaven above and on earth beneath.' Rahab's confession is a formal monotheistic declaration: not merely that YHWH is powerful but that he is the God — <em>hu Elohim</em> (he is God). The formula 'heaven above and earth beneath' is the OT's merism for universal sovereignty: no domain is outside YHWH's jurisdiction. This confession exceeds what many Israelites ever articulated clearly. Rahab functions in the narrative as a witness to YHWH's universal sovereignty — the outsider who sees what the insiders have failed to fully grasp.</p>",
    "12": "<p><strong>chesed</strong> (<em>hesed, H2617</em>): 'loyal love/covenant faithfulness.' Rahab asks the spies to 'do chesed' with her household because she has done <em>chesed</em> with them. <em>Chesed</em> is the covenant loyalty that mirrors YHWH's own character — it is the word used of Ruth's faithfulness to Naomi, of YHWH's faithful love to his people, and of the relationship between covenant partners. Rahab's request for <em>chesed</em> in return for <em>chesed</em> invokes the covenant logic of reciprocal loyalty: she has protected the spies; they owe her protection. <strong>ot emet</strong> (<em>ot, H226; emet, H571</em>): 'a sign of faithfulness' — a confirming token that the promise will be kept.</p>",
    "13": "<p><strong>vehacheyitem et-avi ve'et-immi ve'et-achai ve'et-achotai</strong>: 'you shall let live my father, my mother, my brothers, my sisters.' Rahab's concern is communal — she asks not merely for her own life but for her entire household. The unit of salvation in Joshua is consistently the household (<em>bayit</em>): the Passover was by household (Exod 12:3), the census was by household (Num 1:2), and the Rahab rescue is by household. The household-unit of covenant salvation appears throughout the OT and NT (Acts 11:14 'you and your household will be saved'; 16:31). <strong>nefesh</strong> (<em>nefesh, H5315</em>): 'life/soul/person' — the full living person, not merely the physical survival.</p>",
    "14": "<p><strong>nafshenu tachat-khem lamut</strong>: 'our lives for yours in death.' The spies' oath is a mutual-death pledge: they stake their lives on keeping the promise to Rahab's household. <strong>chesed ve'emet</strong> (<em>hesed, H2617; emet, H571</em>): 'loyal love and faithfulness.' The paired formula <em>hesed ve'emet</em> is a standard expression of covenant commitment in Hebrew — it describes YHWH's character (Exod 34:6: 'abounding in <em>chesed</em> and <em>emet</em>') and the ideal of covenant relationship. The spies are binding themselves with YHWH's own character-words. The irony is pointed: Canaanite Rahab receives a promise given in YHWH's own covenant language from the agents of the nation YHWH is dispossessing.</p>",
    "15": "<p><strong>bevaad hachalon</strong> (<em>bevad, H1157; chalon, H2474</em>): 'through the window.' The window is the point of escape — Rahab's house is built into the city wall (v.15b), and the window that looks outward gives the spies access to the outside world unavailable through the gate. The structural detail (house in the wall) serves the narrative: the escape was through the margin of the city, the threshold between inside and outside. Rahab lives at the threshold — a liminal figure by social status (prostitute), by location (wall), and by covenantal status (Canaanite who fears YHWH). Her position at the margin makes her the instrument of rescue for both the spies and herself.</p>",
    "16": "<p><strong>lechu haharah</strong>: 'go to the hill country.' Rahab's escape instructions are practically sound: the hill country east of Jericho (the wilderness of Judah) offered cover and concealment that the Jordan valley road did not. The three-day hiding period (v.16b) would outlast the search party's pursuit to the Jordan fords. <em>Shalsheset hayamim</em> (three days) — the same period used before the Jordan crossing (Josh 1:11; 3:2), before Jesus's resurrection, and as a general biblical period of transition and transformation. The three-day waiting in the wilderness before re-emerging anticipates the three-day pattern that structures the entire conquest narrative.</p>",
    "17": "<p><strong>niqiyim anachnu mishvu'atecha hazeh</strong>: 'we will be innocent of this oath of yours.' The conditional structure of the oath is carefully articulated: the spies' oath is valid only if Rahab fulfills her part of the agreement (the scarlet cord, the family gathered inside, silence about the mission). The oath logic is the covenant structure: obligation on both parties, with conditions for dissolution. The careful legal framing reflects the seriousness with which the ancient world treated oaths — broken oaths brought blood-guilt on the oath-breaker. The spies are being precise because they intend to keep their word and want the conditions of keeping it clearly specified.</p>",
    "18": "<p><strong>et tikvat chut hashani hazeh tiksheri bevad haChalon</strong>: 'this scarlet cord [<em>tikvat chut hashani</em>] you shall tie in the window.' <em>Tikvah</em> can mean both 'cord/thread' and 'hope' — some patristic interpreters (Justin Martyr, Origen) noted that the word for Rahab's hope (<em>tikvah</em>) is the same as the word for her scarlet cord; her hope and the scarlet cord are linguistically the same thing. Whether or not this wordplay is original, the typological point is clear: the scarlet cord marks the household for salvation as the Passover blood marked the doorposts; those inside are marked safe. Rahab's inclusion in Matthew's genealogy (Matt 1:5) is a Gentile woman's faith being woven into the Messiah's line.</p>",
    "19": "<p><strong>damov beroshov</strong>: 'his blood shall be on his own head.' The blood-guilt formula transfers responsibility to the person who violates the agreement — if anyone goes out of the protected household, the spies bear no blood-guilt for their death. <em>Damov beroshov</em> is the standard Hebrew idiom for self-incurred responsibility (Lev 20:9; Ezek 18:13). The blood-guilt language is significant in light of the scarlet cord: the marking that saves those inside is made in terms of blood (the cord's color) and blood-guilt (the formula for those who violate the terms). The entire Rahab episode is saturated with blood imagery that anticipates the Passover-theology of Christian salvation.</p>",
    "20": "<p><strong>im-tagidi et-dvar hadavar hazeh</strong>: 'if you tell this business of ours.' The oath's final condition: silence about the spy mission. Rahab's cooperation requires not only the scarlet cord and the gathered household but active concealment of the spies' reconnaissance work. The covenant relationship begins with a secret — the spies' business is known only to the parties to the agreement. The secrecy clause is not merely tactical but theological: Rahab's decision to protect the spies is a decision against her city and king, a fundamental reorientation of loyalty. The disclosure clause ensures that the reorientation is complete — there is no half-in position available.</p>",
    "21": "<p><strong>vatikshor et tikvat hashani bachalon</strong>: 'she tied the scarlet cord in the window.' The immediate obedience to the oath-condition: as soon as the spies left, Rahab tied the cord. The immediacy is the narrative's signal of faith — not 'I will do this when the armies arrive' but 'I will do this now.' The scarlet cord hanging in the window is the visible sign of faith in invisible YHWH — a public declaration (visible to anyone looking at the wall) of where Rahab's loyalty has been placed. The cord is both the means of the spies' escape (they descended on it, v.15) and the sign of Rahab's salvation — the same object serves two purposes, exit and entrance into covenant.</p>",
    "22": "<p><strong>va'yavo haharah va'yeshvu sham shloshut yamim</strong>: 'they went to the hill country and stayed there three days.' The wilderness sojourn is brief but structurally significant — three days between Rahab's protection and the return to Joshua, three days between Joshua's announcement and the Jordan crossing, three days of resurrection. The repetition of three-day periods throughout Joshua 1-6 creates a rhythmic pattern of preparation and action: hiding, crossing, marching. The spies who hid in the hills for three days emerge to report faith confirmed — the same pattern as the resurrection witnesses who emerge from the shadow of death to proclaim life.</p>",
    "23": "<p><strong>va'yashvu va'yavo'u el Yehoshua</strong>: 'they returned and came to Joshua.' The report of the spies is the narrative's denouement: what they observed validates the mission's success before it has begun. The movement return-and-report is the standard pattern for sent messengers throughout the OT (Gen 32:7; Num 13:25-26). The spies' obedience — going, hiding, returning, reporting — models the faithful execution of a dangerous commission. Their return also fulfills the implicit narrative tension: we wondered whether they would escape; the three-day hiding resolved the uncertainty before the report. The tension of the narrative is a small-scale type of the larger tension of the conquest: will YHWH's word be fulfilled?</p>",
    "24": "<p><strong>ki natan YHWH beyadenu et kol-ha'aretz</strong>: 'for YHWH has given all the land into our hand.' The spies' report to Joshua is the inverse of the majority report from Numbers 13: there, the spies said 'we are not able'; here, the spies say 'YHWH has given.' The same word <em>natan</em> (given, perfect tense) that Rahab used in her confession to the spies (2:9) is now reported back to Joshua — YHWH's gift declared first by a Canaanite prostitute, confirmed by the two spies, and now the ground of Joshua's confident advance. The conquest begins with Rahab's theology, not Israel's. The one who has been outside the covenant becomes the first to proclaim the covenant's fulfillment.</p>"
  },
  "3": {
    "1": "<p><strong>vayashkem Yehoshua baboqer</strong> (<em>shakam, H7925</em>): 'Joshua rose early in the morning.' <em>Shakam</em> (to rise early, literally 'to put the shoulder to a task at dawn') is used throughout the OT of those who execute YHWH's commands with urgency — Abraham rose early to go to Moriah (Gen 22:3), Moses rose early at Sinai (Exod 24:4), Joshua here. The early rising is the narrative's signal of prompt obedience: the command is received and immediately acted upon. The movement from Shittim to the Jordan and the three-day encampment is the final preparation before the crossing — Israel is positioned at the threshold of the promise before YHWH acts.</p>",
    "2": "<p><strong>miqtze shloshut yamim</strong>: 'at the end of three days.' The three-day transition period concludes with the officers' proclamation. The three-day rhythm of Joshua 1-5 (1:11 announcement, 2:22 hiding, 3:2 crossing) structures the narrative as a series of three-day preparations. The officers (<em>shotrim</em>) serve as the communication layer between Joshua's command and the people's action — the same function they served in ch1. The covenant community's movements are organized, not spontaneous: there is order and communication before every major act of YHWH.</p>",
    "3": "<p><strong>aron haberit YHWH Eloheichem</strong> (<em>aron, H727; berit, H1285</em>): 'the ark of the covenant of YHWH your God.' The ark's full title — ark of the covenant of YHWH — emphasizes both its physical nature (a box) and its theological significance (the container of the covenant, i.e., the tablets of the law). <strong>kohanim halviyim</strong> (<em>kohen, H3548; levi, H3878</em>): 'the Levitical priests.' The priests are carriers, not warriors — the ark leads the crossing and the army follows. The order of march inverts ordinary military logic: the symbol of covenant presence goes first into the dangerous waters. This is the pattern of YHWH's leadership: he enters the danger before his people do.</p>",
    "4": "<p><strong>kivshaltayim amah yihyeh beineichem uvein ha'aron</strong>: 'about 2,000 cubits' distance shall be between you and the ark.' The commanded distance between the people and the ark — approximately 900 meters — is not merely logistical but theological: YHWH's holiness requires respectful distance. <em>Ki lo-y'datem et-haderech asher telu vah</em> (for you have not passed this way before) — the crossing is unprecedented; the unknown road requires following the guide. The unknown way is a recurrent motif in the wilderness and conquest narratives (Deut 8:2: 'the way that YHWH your God led you'). The instruction to observe the ark and not go near it maintains the dialectic of covenant relationship: presence and distance, intimacy and holiness.</p>",
    "5": "<p><strong>hithqaddeshu ki machar ya'aseh YHWH beqirbekhem nifla'ot</strong> (<em>qadash, H6942; nifla'ot, H6381</em>): 'sanctify/consecrate yourselves, for tomorrow YHWH will do wonders among you.' <em>Hithqaddeshu</em> (sanctify yourselves, Hithpael reflexive) is the ritual preparation for encountering divine presence — washing, sexual abstinence, clean garments. The same command was given at Sinai (Exod 19:10-11) before YHWH descended on the mountain. <em>Nifla'ot</em> (wonders, from <em>pala</em>/H6381) refers to the extraordinary acts of YHWH that exceed natural explanation — the same word used for the plagues and the Red Sea crossing. The Jordan crossing is set within the pattern of the great divine acts: what YHWH did at the sea he will do at the river.</p>",
    "6": "<p><strong>se'u et-aron habrit</strong> (<em>nasa, H5375</em>): 'take up the ark of the covenant.' <em>Nasa</em> (lift up, carry) is the standard word for the Levites' carrying of the tabernacle equipment (Num 4:15). The ark is carried on poles through rings — never directly touched — by the Levitical priests. The command <em>viv'ru lifnei ha'am</em> (cross before the people) makes the ark and its carriers the vanguard of the entire nation. The priestly leadership of the crossing — priests in front with the ark — establishes that this is a liturgical act as much as a military one: Israel crosses into the promised land as a worshipping community following the ark of YHWH's covenant, not as an army following its general.</p>",
    "7": "<p><strong>hayom haze achel galedlecha be'einei kol-Yisrael</strong> (<em>gadal, H1431</em>): 'this day I will begin to exalt you in the eyes of all Israel.' <em>Gadal</em> (to be great, to make great) is the word of YHWH's exaltation of his servants — used of YHWH making Abraham great (Gen 12:2), David great (2 Sam 7:9), and Solomon great (1 Kgs 1:37). Joshua's exaltation is not for his own glory but for the people's confidence: they need to know that YHWH has appointed Joshua as Moses's successor. The exaltation comes through the miracle of the Jordan crossing — YHWH authenticates his servant by the same kind of sign he gave through Moses (the Red Sea). The means of establishing leadership is through evident divine action, not human charisma or political appointment.</p>",
    "8": "<p><strong>amdu bevod hayarden</strong> (<em>amad, H5975; yirad, H3383</em>): 'stand still in the Jordan.' The command to the priests to enter the Jordan and stand — not cross but stand in the middle — is the act of faith that triggers the miracle. The priests must first place themselves in the water; only then will YHWH stop it. This is a consistent pattern in the conquest: human obedience precedes divine action. The priests standing in the flowing water while YHWH holds back the flood upstream (3:16) models the faith that acts on the promise before the promise is visible. The standing priests in the Jordan are the type of every act of obedience that positions the community to receive what YHWH has promised.</p>",
    "9": "<p><strong>shimu et divrei YHWH Eloheichem</strong>: 'hear the words of YHWH your God.' The command to hear precedes the miracle — not the miracle that produces faith but the word that commands faith in anticipation of the miracle. <em>Shema</em> (hear/obey) is the central act of covenant relationship (Deut 6:4). <strong>bo tekru ki El chai beqirbekhem</strong> (<em>El chai, H410+2416</em>): 'know that the living God is among you.' <em>El chai</em> (living God) contrasts YHWH with the dead idols — he is alive, active, present. The title 'living God' appears at moments of YHWH's most direct intervention: the Jordan crossing, Elijah's confrontation with Baal (1 Kgs 18:10), and Daniel's rescue from the lions (Dan 6:20).</p>",
    "10": "<p><strong>harosh tirash... Kena'ani vehachiti vehaHivi vehaperizzi vehaGirgashi veha'Emori vehYevusi</strong>: 'he will certainly dispossess — the Canaanite, the Hittite, the Hivite, the Perizzite, the Girgashite, the Amorite, and the Jebusite.' The sevenfold list of peoples is the standard formula for the inhabitants of Canaan (found in Exod 3:8; 23:23; Deut 7:1). The number seven suggests completeness — all the peoples of the land, without remainder. <em>Yarosh tirosh</em> (the infinitive absolute construction intensifying the verb: 'dispossessing he will dispossess') is the emphatic affirmation: the outcome is certain. The list functions as the divine promise that every named people-group will yield to Israel's conquest — the naming makes the promise specific rather than general.</p>",
    "11": "<p><strong>aron habrit adon kol-ha'aretz</strong> (<em>adon, H113; kol-ha'aretz, H3605+776</em>): 'the ark of the covenant of the Lord of all the earth.' The title <em>adon kol-ha'aretz</em> (Lord of all the earth) is rare and important — it establishes YHWH's universal sovereignty as the theological foundation for the conquest. The Canaanites' gods were local deities; YHWH is the God of the whole earth, which is why his claim on Canaan supersedes the existing inhabitants' claims. The title appears again at the Red Sea (Ps 97:5) and in Zechariah's eschatological vision (Zech 4:14; 6:5). The ark — the container of the covenant — represents YHWH himself going before the army; it is not merely a symbol but the localized presence of the universal Lord.</p>",
    "12": "<p><strong>qechu lachem shnei asar anashim</strong>: 'take for yourselves twelve men.' The twelve men, one from each tribe, are prepared here for the memorial stones command of ch4. The number twelve is the structural number of Israel's covenant identity — the twelve tribes, the twelve spies, the twelve apostles. The selection of one man from each tribe ensures that the memorial will belong to all Israel, not merely the vanguard tribes or the leadership. The twelve-stone memorial to be built at Gilgal will be Israel's perpetual witness to YHWH's faithfulness — corporate, all-tribal, permanent.</p>",
    "13": "<p><strong>notchu mayim hayarden miymahal</strong> (<em>karat, H3772; notach/natach, H5140</em>): 'the waters of the Jordan shall be cut off.' <em>Yikkaretu</em> (they will be cut off) uses the same root as <em>karet</em> (cut off/cut a covenant) — the waters will be 'covenant-cut,' severed. The technical language of covenant-making (cutting a covenant = <em>karat berit</em>) applied to the dividing of waters is theologically suggestive: the Jordan crossing is a covenant act, not merely a military maneuver. <em>Yaqumu ned echad</em> (they will stand in a heap): the same word used for the Red Sea waters (Exod 15:8; Ps 78:13) — the Jordan crossing is explicitly a re-enactment of the Sea crossing, confirming that YHWH's acts form a coherent story.</p>",
    "14": "<p><strong>vaysmu ha'am misholeihem la'avor et-hayarden</strong>: 'the people set out from their tents to cross the Jordan.' The movement of an entire nation to cross a river — hundreds of thousands of people in an organized procession, the ark of the covenant at their head, priests in the water waiting, the river held back — is one of the most visually dramatic moments in the OT. The narrative's restraint (it does not pause to describe the spectacle) reflects the biblical style of understatement in the face of the miraculous: the miracle is reported simply, without embellishment, as if it were entirely expected. YHWH does what he said he would do; the surprise would be if he did not.</p>",
    "15": "<p><strong>al sefot hayarden male al-kol gdefotav kol yemei qatzir</strong>: 'the Jordan overflows all its banks throughout the harvest season.' The timing detail — flood season at harvest (April/May, the barley harvest) — increases the magnitude of the miracle. The Jordan in flood is not a trickling stream but a significant river running over its banks; stopping it at peak flood is a greater demonstration than at low water. The same detail tells us the timing aligns with Passover: the first Passover in Canaan (5:10) occurs during barley harvest. The Jordan crossing during the flood and the Passover celebration in Gilgal are two moments of the same holy season — the season of Israel's liberation ritually enacted in their entry into the land.</p>",
    "16": "<p><strong>vayamdu ha'am miv'Reicho ad Adam ha'ir asher eltzad Tzaretan</strong>: 'the waters rose in a heap far away, at Adam, the city beside Zaretan.' The specific location — Adam (modern Tell ed-Damiyeh) — is approximately 25-30 km upstream from the Jordan-Dead Sea junction. The precision is the narrative's claim to historicity: this happened at a specific identifiable place, not in mythological space. The city of Adam is named for its location near the Jordan's first great narrowing — a topographical choke-point where a landslide dam would have the most dramatic effect. The natural geography and the supernatural act cooperate in the text without tension: YHWH can use the land's topography for his purposes.</p>",
    "17": "<p><strong>kohanim nos'ei aron habrit YHWH amdu betoch hayarden al-yabbashah</strong> (<em>yabbashah, H3004</em>): 'the priests who carried the ark of the covenant of YHWH stood on dry ground in the middle of the Jordan.' <em>Yabbashah</em> (dry ground) is the same word used of the land that appeared when YHWH separated the waters in Gen 1:9 and of the Red Sea dry-crossing (Exod 14:16,22). The three-fold dry-crossing (creation, Red Sea, Jordan) forms a typological sequence: in the beginning YHWH made dry land from water; at the Exodus he made dry ground through water for Israel; at the Jordan he makes dry ground in water for the conquest generation. Each crossing replicates the pattern of creation: YHWH brings order (dry land/crossing) out of chaos (water/obstacle).</p>"
  },
  "4": {
    "1": "<p><strong>vayehi ke'asher tamu kol-hagoy la'avor et-hayarden</strong>: 'when all the nation had finished crossing the Jordan.' The completion formula marks the end of the crossing and the beginning of the memorial instruction. The entire nation crossing — not a vanguard but all the people — is the narrative's emphasis on completeness: YHWH's act of redemption encompasses all of Israel, not merely the capable fighters. The crossing is completed in a single day, the crowds moving efficiently on the divinely-maintained dry riverbed. The completion before the memorial instruction signals that the monument will celebrate a finished act, not an ongoing miracle — the stones record what YHWH has done, not what he is doing.</p>",
    "2": "<p><strong>qechu lachem min-ha'am shnei asar anashim</strong>: 'take from the people twelve men.' The twelve men pre-selected in 3:12 now receive their specific task: retrieving the twelve stones from the riverbed where the priests stood. The one-man-per-tribe structure ensures that the memorial is nationally representative — every tribe contributes one stone, so every tribe's history is bound up in the single monument at Gilgal. The tribal representation in the memorial serves the same function as the tribal structure in the census and the spy mission: YHWH's acts are acts for all Israel, and all Israel participates in commemorating them.</p>",
    "3": "<p><strong>hatiru lachem mizeh mitoch hayarden mitachat raglei hakohanim</strong>: 'take up from here, from the middle of the Jordan, from the place where the priests' feet stood.' The memorial stones are taken from the exact spot of the miracle — not from the riverbank but from the riverbed under the priests' feet. The specificity ensures that the stones are evidence, not merely representative tokens: these particular stones bear the marks of the place where YHWH's act was concentrated. The memorial's power is testimonial, not magical — they are stones from the place, not stones with power. But their origin in the Jordan's bed makes them irreplaceable witnesses to the specific act of YHWH on a specific day.</p>",
    "4": "<p><strong>vayiqra Yehoshua el-shnei asar ha'anashim</strong>: 'Joshua called the twelve men.' The calling of the representatives is Joshua's executive act — he identifies the pre-selected twelve and gives them their specific mission. The command structure is now fully operational: YHWH commanded Joshua (3:7-8), Joshua commanded the officers (1:10-11), Joshua now personally calls the twelve. Leadership in the conquest is both hierarchical (Joshua below YHWH, above the officers) and direct (Joshua personally engages key individuals for key tasks). The combination of authority and personal engagement is the model of covenant leadership throughout the OT.</p>",
    "5": "<p><strong>ivru lifnei aron YHWH Eloheichem el-toch hayarden</strong>: 'cross before the ark of YHWH your God into the middle of the Jordan.' The command to cross 'before' the ark — that is, ahead of it, into the riverbed — requires that the twelve trust the miracle they are standing in. They must pick up stones while the river is still held back by the priests standing upstream. The act of faith is not dramatic but practical: bending down, picking up a stone, carrying it out. The mundane action (picking up a stone) is performed in a miraculous context (a dry riverbed in flood season) — a pattern throughout Joshua of ordinary obedience in extraordinary circumstances.</p>",
    "6": "<p><strong>lema'an tihyeh zot ot bekirbekhem</strong> (<em>ot, H226</em>): 'that this may be a sign among you.' <em>Ot</em> (sign/marker) is the word for covenant signs throughout the OT — the rainbow (Gen 9:12-13), circumcision (Gen 17:11), Sabbath (Exod 31:13,17). The twelve stones become a covenant sign: visible, permanent, generationally transmissible. <em>Ki yish'alun benikhem machar</em> (when your children ask in the future): the interrogative-catechetical function of the memorial anticipates the children's question and provides the answer in advance. The monument is the occasion for teaching, not merely the record of an event — it exists to produce the catechetical moment across generations.</p>",
    "7": "<p><strong>zikaron libnei Yisrael ad-olam</strong> (<em>zikaron, H2146</em>): 'a memorial for the children of Israel forever.' <em>Zikaron</em> (memorial) is the covenant memory-object — the Passover is a <em>zikaron</em> (Exod 12:14), the two memorial stones on the high priest's ephod are <em>zikaronot</em> (Exod 28:12). To be remembered is to be covenant-present — not merely in the past but in ongoing relationship. The Jordan stones are a <em>zikaron</em> of YHWH's act, which is simultaneously YHWH's identity as the God who acts for his people. The memorial 'forever' (<em>ad-olam</em>) means as long as Israel is Israel — the covenant relationship lasts as long as the covenant people exist.</p>",
    "8": "<p><strong>vayasimu el-hamalon vayanichu sham</strong>: 'they set them down in the place where they lodged and left them there.' The stones are deposited at Gilgal, the first encampment in the promised land. The movement stones → Gilgal creates the permanent monument: twelve river-bottom stones in the middle of a camp. The contrast between the stones' origin (the Jordan riverbed, the place of miraculous crossing) and their destination (Gilgal, the site of the first night in Canaan) marks the transition from wilderness to inheritance. The same act that commemorates the crossing also marks the commencement of the new era — Gilgal is simultaneously the end of the wilderness and the beginning of the conquest.</p>",
    "9": "<p><strong>ushtei esreh avanim hekim Yehoshua betoch hayarden</strong>: 'Joshua also set up twelve stones in the middle of the Jordan.' A second set of twelve stones is erected in the riverbed itself — under the water — where the priests' feet had stood. This second monument is invisible (submerged) but its existence is known to Israel. The two monuments form a pair: one visible (Gilgal) and one invisible (Jordan), one accessible and one inaccessible, one for permanent display and one hidden under the flowing water. The invisible memorial in the Jordan is the foundation of the visible memorial at Gilgal — the hidden act of YHWH undergirds the visible testimony to it.</p>",
    "10": "<p><strong>ve'hamshehu har Yehoshua el-ha'am vatiyam</strong>: 'and Joshua urged the people, and they hurried.' <em>Heish</em> (hurried/rushed) is the word of urgent action. The priests remain in the middle of the Jordan until every command has been executed: the twelve stones removed, the armed tribes having crossed, the whole congregation having passed. Only then does Joshua give the priests permission to come up (v.17). The priests' patient standing in the riverbed while the entire nation crosses around them is a model of servant leadership: they remain at their post not for their own glory but until the community's need is fully met.</p>",
    "11": "<p><strong>vayavo aron YHWH vehakohanim lifnei ha'am</strong>: 'the ark of YHWH and the priests crossed before the people.' After all Israel had crossed, the ark crosses — not first but last. The order is reversed from the entry: the ark went first into the water (3:15) and comes out last. The ark is the first to stand in the Jordan (committing to the miracle) and the last to leave (not departing until the people are safe). This sequence models YHWH's care: he enters before his people and exits after them, enveloping the people's crossing between his entrance and exit. The ark's movement is YHWH's movement — first into the danger, last out of it.</p>",
    "12": "<p><strong>vaya'avru livnei Reuven uvnei Gad vechatzi shevet Menashe chalutzim</strong> (<em>chalutz, H2502</em>): 'the sons of Reuben, Gad, and half of Manasseh crossed over armed.' <em>Chalutzim</em> (armed/equipped, lit. 'the drawn ones,' from the act of drawing a weapon) refers to the combat-ready vanguard. The trans-Jordan tribes fulfilled their Numbers 32 commitment — their soldiers crossed with Israel. The detail confirms covenant fidelity: a promise made by Moses is kept by Joshua's generation. The covenant community's reliability depends on each component fulfilling its obligations. The trans-Jordan fighters' presence 'before the sons of Israel' places the settled tribes in the service of the unsettled ones.</p>",
    "13": "<p><strong>ke'arbaim elef chalutze hatzava avru lifnei YHWH</strong>: 'about forty thousand armed warriors crossed before YHWH.' The number forty thousand represents the combat-ready Reubenites, Gadites, and half-Manassites. The phrase <em>lifnei YHWH</em> (before YHWH) treats the crossing as a liturgical act of presentation before the divine king — the warriors cross in YHWH's presence as much as in Israel's sight. Every act of the conquest is simultaneously a military operation and a covenantal liturgy: the warriors are presenting themselves to YHWH for service in his cause, not merely executing a military campaign.</p>",
    "14": "<p><strong>vayigadel YHWH et-Yehoshua be'einei kol-Yisrael</strong>: 'YHWH exalted Joshua in the eyes of all Israel.' The fulfillment of the promise in 3:7 ('this day I will begin to exalt you'). The verb <em>gadal</em> (to be great, to exalt) is in the Piel (intensive) — YHWH actively, deliberately made Joshua great. The exaltation is by evidence: the Jordan crossing, commanded by Joshua and executed under his leadership, demonstrates that YHWH is with Joshua as he was with Moses. <em>Vayir'uhu</em> (they feared him): the reverential fear of Joshua that follows his exaltation is the same fear the people gave Moses. Leadership in Israel is grounded in YHWH's authentication, not in popular vote or military success.</p>",
    "15": "<p><strong>vayomer YHWH el-Yehoshua le'mor</strong>: 'YHWH spoke to Joshua, saying.' The standard divine-speech formula marks each new command — YHWH's ongoing direction of the crossing through Joshua. The direct speech of YHWH to Joshua (which Joshua then relays to the priests) models the chain of command that is the conquest's governing structure. YHWH speaks, Joshua hears and obeys, the priests obey Joshua, the people follow the priests. The entire operation is sustained by this chain of hearing and obeying; any break in the chain would halt YHWH's purpose. The formula 'YHWH said to Joshua' appears thirteen times in the book — the conquest is executed instruction by instruction.</p>",
    "16": "<p><strong>tzav et-hakohanim nose'ei aron ha'edut viya'alu min-hayarden</strong>: 'command the priests who carry the ark of the testimony to come up out of the Jordan.' <em>Aron ha'edut</em> (ark of the testimony) uses the alternative designation for the ark — the testimony (<em>edut</em>) being the two tablets of the covenant inscribed with the Ten Words. The ark of the covenant and the ark of the testimony are the same object described by its contents; the testimony-designation emphasizes that it contains YHWH's legal requirements for the covenant. The priests who carry the testimony come up from the Jordan — emerging from the crossing with the covenant document intact, the law having passed through the waters as securely as the people.</p>",
    "17": "<p><strong>tzav et-hakohanim alot min-hayarden</strong>: 'command the priests to come up from the Jordan.' The second, direct command to Joshua to release the priests from their standing position. The repetition (vv.16 and 17) emphasizes the deliberate nature of the release — the priests did not come out when the last Israelite crossed; they waited for explicit divine permission. The discipline of waiting at one's appointed post until released by proper authority is the model of the covenant servant. The priests' patient standing while the river was held, waiting to be dismissed, demonstrates the full execution of the command — not merely following the letter but maintaining the posture until the purpose is achieved.</p>",
    "18": "<p><strong>vayashov mei-hayarden limqomam vayelkhu kimtmol shilshom al-kol-gdefotav</strong>: 'the waters of the Jordan returned to their place and overflowed all its banks as before.' The restoration of the flood at the moment the priests' feet lifted from the riverbed confirms YHWH's precise control — the water held while the priests stood and returned the moment they left. The phrase <em>kimtmol shilshom</em> (as yesterday and the day before — idiom for 'as usual') marks the return to normal: the miracle was bounded, precise, and complete. The flood that had been held back for the entire crossing rushes back, sealing the crossing as a finished act. There is no gradual return, no lingering miracle — the act is complete and YHWH's ordinary governance of the world resumes.</p>",
    "19": "<p><strong>ubnei Yisrael chanu baGilgal birtzet yericho</strong> (<em>Gilgal, H1537</em>): 'the children of Israel camped at Gilgal on the eastern border of Jericho.' Gilgal becomes the base camp for the conquest — Israel returns here after each campaign. The name <em>Gilgal</em> is explained in 5:9: it means 'rolling,' from the act of rolling away Israel's reproach. It becomes one of the most important sites in later Israelite history: Samuel judged there (1 Sam 7:16), Saul was made king there (1 Sam 11:15), Elijah and Elisha ministered there (2 Kgs 2:1). The base camp of the conquest becomes the administrative center of early monarchy and the prophetic training center — the significance of Gilgal grows through the OT.</p>",
    "20": "<p><strong>et shnei esreh ha'avanim haeleh asher laqu min-hayarden hekim Yehoshua baGilgal</strong>: 'Joshua set up these twelve stones which they had taken from the Jordan.' The erection of the memorial is the narrative's culmination of the crossing sequence. The stones from the riverbed, carried by the twelve tribal representatives, set up by Joshua at the first campsite — the memorial combines divine act (the crossing), human representation (twelve tribes), and human memory (the monument). The monument is not a sanctuary but a <em>zikaron</em> — a memorial to a historical act. The distinction is important: Israel does not worship at the stones but tells the story of what YHWH did. The monument serves the story, not the story the monument.</p>",
    "21": "<p><strong>ki yish'alun b'neikhem machar et avotam</strong>: 'when your children ask their fathers in the future.' The interrogative framework — children asking, fathers answering — is the catechetical structure of Passover Haggadah and Deuteronomy (Deut 6:20-25). The monument exists to provoke the question that enables the story. Without the question, the stones are just stones; with the question, they become the occasion for transmitting the founding narrative to the next generation. The future orientation of the monument — <em>machar</em> (tomorrow/the future) — means the twelve stones are not for the generation that crossed but for every generation that comes after. The covenant community is defined as the community that tells this story to its children.</p>",
    "22": "<p><strong>yavesh YHWH Eloheichem et-mei hayarden mipneikhem</strong>: 'YHWH your God dried up the waters of the Jordan before you.' The catechetical answer provided in advance: YHWH dried the Jordan as he dried the Red Sea (Exod 14:21; 15:19). The answer is Trinitarian in structure: <em>YHWH your God</em> is the actor; <em>the Jordan</em> is the object; <em>before you</em> is the purpose. The answer to the children's question is a confession of faith: YHWH is the kind of God who dries rivers for his people, as he dried seas before them. The catechism produces covenant identity: to know this story is to know who we are and who our God is.</p>",
    "23": "<p><strong>ka'asher asah YHWH leYam-Suf asher hovish mipneinu</strong>: 'as YHWH did to the Red Sea, which he dried up before us.' The explicit connection between the Jordan crossing and the Red Sea crossing is the interpretive key to both: the Jordan is a second Exodus, the conquest is a second liberation, and Joshua is a second Moses. The <em>ka'asher</em> (as/just as) comparison signals typological repetition: YHWH acts now as he acted then; the pattern of his saving acts is consistent. This is the OT's own hermeneutic of the acts of YHWH — later acts are explained by earlier ones, and earlier ones are fulfilled by later ones. The pattern is the revelation.</p>",
    "24": "<p><strong>lema'an da'at kol-amei ha'aretz et-yad YHWH ki chazaqah hi</strong> (<em>yad YHWH, H3027; chazaq, H2389</em>): 'that all peoples of the earth may know that the hand of YHWH is mighty.' The universal evangelistic purpose of the Jordan crossing: not merely to bring Israel into the land but to demonstrate YHWH's power to all nations. <em>Yad YHWH</em> (the hand of YHWH) is the standard idiom for YHWH's active power in history — the same hand that struck Egypt (Exod 7:4) and divided the Red Sea (Exod 14:31). <em>Uv'an tiru'u et-YHWH Eloheichem kol-hayamim</em> (and that you might fear YHWH your God always) — the universal knowledge of YHWH's power produces the fear of YHWH in Israel. The miracle is simultaneously outward witness and inward formation.</p>"
  },
  "5": {
    "1": "<p><strong>vayamas libbam velo-hayah vodam od mipnei benei Yisrael</strong> (<em>maqaq, H4549; ruach, H7307</em>): 'their hearts melted and there was no longer any spirit in them.' <em>Maqaq</em> (melted, dissolved) describes the total collapse of the will before overwhelming fear — the same word used of Israel's opponents in Rahab's confession (2:9). <em>Ruach</em> (spirit/breath/resolve) draining out — the idiom for losing the will to resist. The Amorite and Canaanite kings' terror upon hearing of the Jordan crossing confirms YHWH's earlier promise: 'I will send my terror before you and throw into confusion all the people against whom you shall come' (Exod 23:27). The conquest succeeds because YHWH pre-softens the resistance; Israel's military action operates in a field already prepared by YHWH's terror.</p>",
    "2": "<p><strong>asih lecha charbot tzorim vashav mul et-benei Yisrael sheynit</strong> (<em>charlot tzorim, H2719+6864; mul, H4135</em>): 'make flint knives and circumcise the children of Israel a second time.' <em>Charbot tzorim</em> (flint knives) — stone implements rather than bronze, preserving the ancient practice (Exod 4:25 used a flint for Zipporah's circumcision). The flint may reflect the antiquity and solemnity of the rite, or its association with the rock (YHWH as rock). <em>Shub mul</em> (circumcise again) — not re-circumcising those already circumcised but circumcising the uncircumcised generation. The conquest generation must be circumcised before fighting in YHWH's name: the covenant sign must mark the warriors before they can serve as YHWH's instrument.</p>",
    "3": "<p><strong>vayyamal Yehoshua et-benei Yisrael el-Givat ha'Aralot</strong> (<em>aralah, H6188</em>): 'Joshua circumcised the children of Israel at Gibeath-haaraloth.' <em>Givat ha'Aralot</em> (Hill of the Foreskins) — named for the event that occurred there, like Kibroth-hattaavah (graves of craving) and Taberah (burning) in Numbers. The place-name is deliberately unglamorous: the hill of circumcision is not a name of glory but of covenant marking. The physical act of circumcision at Gilgal — cutting and burying the foreskins — is the covenant surgery that distinguishes Israel from the nations. The conquest army is an army of covenant-marked men, not merely trained fighters.</p>",
    "4": "<p><strong>hadavar asher-mal Yehoshua kol-ha'am hayotzei mimitzrayim</strong>: 'the reason Joshua circumcised: all the males who came out of Egypt.' The narrative explains the mass circumcision: the entire wilderness generation's males had been circumcised at the Exodus, but the wilderness years produced an entire generation that had never been circumcised. The explanation is given with precision: those who came out of Egypt were circumcised; those born in the wilderness were not. The gap in the covenant sign corresponds to the gap in the covenant relationship — the wilderness generation's unbelief was expressed in, among other things, their failure to circumcise their sons. The new generation must begin their life in the land as fully covenant-marked men.</p>",
    "5": "<p><strong>ki nimolim hayu kol-ha'am hayotzei</strong>: 'all the people who came out had been circumcised.' The contrast between the circumcised exodus generation and the uncircumcised wilderness generation is the covenant gap that Gilgal fills. The circumcision at Gilgal is not merely a ritual requirement but a covenantal reset: the new generation entering the land must be fully covenant-marked before they can fight in YHWH's name. The uncircumcised cannot participate in the Passover (Exod 12:48) — and the Gilgal Passover (5:10) immediately follows the circumcision, confirming that the sequence is deliberate: covenant mark → covenant meal → conquest begins.</p>",
    "6": "<p><strong>arbaim shanah helechu benei Yisrael bamidbar</strong> (<em>midbar, H4057</em>): 'forty years the children of Israel walked in the wilderness.' The forty years summarized: the wilderness generation (the men of war who came out of Egypt) died there, as YHWH had declared at Kadesh (Num 14:28-35). The generation that failed to believe the promise could not enter the land; the generation that was born in the wilderness inherits the promise without inheriting the failure. The contrast between the dead first generation and the living second generation is the pivot of the Pentateuch-to-Joshua transition: from the generation of the covenant-breakers to the generation of the covenant-inheritors. The wilderness is the place between — between liberation and inheritance, between promise and fulfillment.</p>",
    "7": "<p><strong>ve'et-benehem hekim tachtam otam mal Yehoshua</strong>: 'their children he raised up in their place, and Joshua circumcised them.' <em>Hekim tachat</em> (raised up in the place of) — the standard language of succession and replacement. The second generation stands in the place of the first, inheriting both the promise and the obligation. Circumcision is the act that formally inaugurates them as covenant-bearers — they receive the sign that marks them as the community of the promise. The intergenerational transfer is complete: the dead generation is replaced not by outsiders but by their own children, who now step into the covenant identity that their fathers held imperfectly.</p>",
    "8": "<p><strong>vayehi ka'asher tamu kal-hagoy lehimol va'yeshvu tachtam bamahaneh ad cheyotam</strong>: 'when the circumcision of all the people was finished, they remained in their places in the camp until they were healed.' The practical vulnerability of the circumcision period — the entire fighting force temporarily incapacitated — is a test of faith in YHWH's protection. The Canaanite kings' terror (5:1) created the protective window: YHWH pre-emptively froze the opposition so Israel could complete the covenant requirement without military vulnerability becoming fatal. The nation that lies healing at Gilgal is protected not by its own strength but by YHWH's prior work of terror in the enemy's hearts.</p>",
    "9": "<p><strong>galoti et-cherpat Mitzrayim me'aleichem</strong> (<em>galal, H1556; cherpah, H2781</em>): 'I have rolled away the reproach of Egypt from you.' The etymology of <em>Gilgal</em>: from <em>galal</em> (to roll) — YHWH has rolled away Israel's reproach. <em>Cherpat Mitzrayim</em> (the reproach of Egypt) refers to the shame of slavery — the humiliation of being YHWH's covenant people and yet enslaved, the mockery of the nations who said 'your God brought you out to die in the wilderness.' At Gilgal, with the covenant sign restored and the land entered, the reproach is gone: Israel is no longer the uncircumcised slaves of a foreign power but the covenant-marked conquerors of YHWH's promised land. The name Gilgal is forever the memorial of this covenantal turning point.</p>",
    "10": "<p><strong>vaya'asu bnei Yisrael et-hapesach be'arbaah asar yom lachodesh ba'erev</strong> (<em>pesach, H6453</em>): 'the children of Israel kept the Passover on the fourteenth day of the month in the evening.' The Passover at Gilgal is the third Passover recorded in the OT (Exod 12, Num 9, Josh 5). It falls on the 40th anniversary of the first Passover — exactly forty years later, on the same calendar date. The Passover commemorates the liberation from Egypt; observed in Canaan, it simultaneously looks back (liberation) and celebrates fulfillment (the promise kept). The covenant meal at the threshold of the promised land ties the two Passovers together: the blood that delivered Israel from Egypt is the same covenant that delivers them into Canaan.</p>",
    "11": "<p><strong>vayochelu meauvr ha'aretz mimakhorat hapesach matzot uqalui</strong> (<em>avur/tavur, H5669; matzot, H4682; qali, H7039</em>): 'they ate the produce of the land, unleavened cakes and parched grain.' <em>Avur ha'aretz</em> (the produce/yield of the land) — the first Canaanite harvest consumed by Israel; the transition from manna (YHWH's direct provision) to the land's natural yield. <em>Matzot</em> (unleavened bread) and <em>qali</em> (parched/roasted grain) are the traditional foods of harvest and Passover — in the same meal, Israel eats the Passover provision (matzot) and the first fruits of the promised land (qali). The combination marks the transition: the feast of liberation is now celebrated in the land of fulfillment.</p>",
    "12": "<p><strong>vayishbot hamman mimokhorat be'aklam meauvr ha'aretz</strong> (<em>shavat, H7673</em>): 'the manna stopped on the day after they ate the produce of the land.' <em>Shavat</em> (stopped, ceased, rested) — the same root as <em>Shabbat</em> (sabbath/rest). The manna's cessation is a sabbath of provision: the supernatural provision that sustained Israel through the wilderness rests when the natural provision of the land begins. The forty-year provision of manna was precisely calibrated to the wilderness period — not one day more, not one day less. YHWH's provision is always exactly sufficient for the situation; when the situation changes, the provision changes with it. The manna's stopping is not an abandonment but a transition — from wilderness provision to covenantal inheritance.</p>",
    "13": "<p><strong>vayisa Yehoshua einav vayar vehineh ish omed lenegdo vechervo shlufa beyado</strong> (<em>ish, H376; cherev, H2719; shlufah, H7619</em>): 'Joshua lifted his eyes and saw: a man standing opposite him with his drawn sword in his hand.' The <em>ish</em> (man) who appears to Joshua near Jericho is the mysterious figure identified as 'the commander of YHWH's army' (v.14). The drawn sword signals readiness for battle — but whose battle? The dramatic question 'are you for us or for our adversaries?' (v.13) positions the encounter as the narrative's most important interpretive moment: the conquest belongs to YHWH, not to Joshua.</p>",
    "14": "<p><strong>lo ki ani sar-tzva-YHWH atah vati</strong> (<em>sar, H8269; tzva, H6635</em>): 'no, but I am the commander of YHWH's army; now I have come.' <em>Sar-tzva-YHWH</em> (commander of YHWH's army/host) — the title for the one who leads the heavenly armies into battle. The divine warrior who will fight for Israel is not a human general but a heavenly commander. <strong>vayipol Yehoshua el-panav artza</strong>: 'Joshua fell on his face to the ground.' The prostration is the correct response to an encounter with the divine — the same response of Ezekiel (Ezek 1:28), Daniel (Dan 8:17), and John (Rev 1:17). Joshua's act of worship before the commander marks the conquest as a religious event: he who was Balaam (confronted by an angel with a drawn sword) receives YHWH's own commander.</p>",
    "15": "<p><strong>shal-na'alcha me'al raglecha ki hamaqom asher atah omed alav qadosh hu</strong> (<em>na'al, H5275; qadosh, H6918</em>): 'take off your sandal from your foot, for the place where you are standing is holy.' The command mirrors Moses at the burning bush (Exod 3:5) — word for word the same: <em>shal na'alecha me'al raglecha</em>. The identical command at the beginning of Moses's mission and at the beginning of Joshua's conquest signals the typological continuity: the one who appeared to Moses at Horeb now appears to Joshua at Gilgal. The holy ground of Sinai and the holy ground of Gilgal are both places of divine commissioning. Joshua removing his sandals is the act of covenant submission: the conqueror of Canaan begins his campaign in the posture of the servant before the divine Commander.</p>"
  }
}

def main():
    existing = load_comm('original', 'joshua')
    merge_comm(existing, JOSHUA)
    save_comm('original', 'joshua', existing)
    total = sum(len(existing.get(ch, {})) for ch in ['1','2','3','4','5'])
    print(f'ch 1-5: {total} verses in output')
    print('Joshua 1-5 original commentary written.')

if __name__ == '__main__':
    main()
